-- Fix: anon INSERT policies voor contactformulieren
DO $$ BEGIN
  CREATE POLICY "Iedereen kan een bericht insturen"
    ON contact_berichten FOR INSERT TO anon WITH CHECK (true);
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

DO $$ BEGIN
  CREATE POLICY "Iedereen kan een inschrijving indienen"
    ON inschrijvingen FOR INSERT TO anon WITH CHECK (true);
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

DO $$ BEGIN
  CREATE POLICY "Iedereen kan een bestelling plaatsen"
    ON shop_bestellingen FOR INSERT TO anon WITH CHECK (true);
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

